import data from '@/armor.json';
import _ from 'lodash';

export default {
  namespaced: true, // 启用命名空间

  state: {
    list: data,
  },

  mutations: {
    // F(state, data) {},
  },

  actions: {
    // f({ commit }) {},
  },

  getters: {
    // 过滤无用的数据
    armorList(state) {
      const blacklist = ['表', '补给卡片', '皮肤道具_TEST[艾利克斯]1', '皮肤道具_TEST[艾利克斯]2'];

      const type = [6, 11];

      const arr = state.list.filter(item => {
        return !(type.includes(item.Type) && blacklist.includes(item.Name));
      });

      return arr;
    },
  },
};
