import data from '@/weapon.json';
import _ from 'lodash';

export default {
  namespaced: true, // 启用命名空间

  state: {
    list: data,
  },

  mutations: {
    F(state, data) {},
  },

  actions: {
    f({ commit }) {},
  },

  getters: {
    // 过滤无用的数据
    weaponList(state) {
      const arr = state.list.filter(
        item =>
          !(
            item.Name.includes('npc用') ||
            item.Name.includes('练习用') ||
            item.Name.includes('???????')
          )
      );

      return arr;
    },
  },
};
